-- Migração dos 210 clientes para o Supabase
-- Execute no SQL Editor do Supabase Dashboard

ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- ESTRUTURA NECESSÁRIA DA TABELA CLIENTES (execute antes se ainda não existir)
-- ============================================================
CREATE TABLE IF NOT EXISTS clientes (
  id            BIGINT PRIMARY KEY,
  rep_id        UUID REFERENCES auth.users(id) ON DELETE CASCADE,
  nome          TEXT NOT NULL,
  razao_social  TEXT,
  fantasia      TEXT,
  cnpj          TEXT,
  comprador     TEXT,
  telefone      TEXT,
  email         TEXT,
  endereco      TEXT,
  cidade        TEXT,
  cep           TEXT,
  lat           NUMERIC,
  lng           NUMERIC,
  segmento      TEXT,
  ultima_visita DATE,
  ultima_obs    TEXT DEFAULT '',
  criado_em     TIMESTAMPTZ DEFAULT now()
);

-- RLS — isolamento total por rep_id
ALTER TABLE clientes ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Rep lê seus clientes" ON clientes;
CREATE POLICY "Rep lê seus clientes" ON clientes
  FOR SELECT TO authenticated USING (rep_id = auth.uid());

DROP POLICY IF EXISTS "Rep insere seus clientes" ON clientes;
CREATE POLICY "Rep insere seus clientes" ON clientes
  FOR INSERT TO authenticated WITH CHECK (rep_id = auth.uid());

DROP POLICY IF EXISTS "Rep atualiza seus clientes" ON clientes;
CREATE POLICY "Rep atualiza seus clientes" ON clientes
  FOR UPDATE TO authenticated USING (rep_id = auth.uid());

DROP POLICY IF EXISTS "Rep deleta seus clientes" ON clientes;
CREATE POLICY "Rep deleta seus clientes" ON clientes
  FOR DELETE TO authenticated USING (rep_id = auth.uid());

